private void xrTableCell28_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal saleableChicks = 0;
decimal settedEggs = 0;

// --- SaleableChicks ---
if (GetCurrentColumnValue("SaleableChicks") != null)
    saleableChicks = Convert.ToDecimal(GetCurrentColumnValue("SaleableChicks"));

// --- SettedEggs ---
if (GetCurrentColumnValue("SettedEggs") != null)
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

// --- Equation ---
decimal percentage = 0;
if (settedEggs != 0)
    percentage = (saleableChicks * 100m) / settedEggs;
    SaleableChicksPercReport += percentage 
// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00"); // 2 decimals, adjust format if needed

}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
